public class ArrayExample {
  public static void main(String[] args) {
    int[] numbers = {10, 20, 30, 40, 50};
    String message = "İlk element: " + numbers[0];
    System.out.println(message);
    message = "Massivin uzunluğu: " + numbers.length;
    System.out.println(message);
    for (int i = 0; i < numbers.length; i++) {
      System.out.println("Element " + i + ": " + numbers[i]);
    }
  }
}
// Çıxış:
// İlk element: 10
// Massivin uzunluğu: 5
// Element 0: 10
// Element 1: 20
// Element 2: 30
// Element 3: 40
// Element 4: 50

public class MultiDimensionalArray {
  public static void main(String[] args) {
    int[][] matrix = {
      {1, 2, 3},
      {4, 5, 6},
      {7, 8, 9}
    };
    String message = "Matrix elementi [1][1]: " + matrix[1][1];
    System.out.println(message);
    for (int i = 0; i < matrix.length; i++) {
      for (int j = 0; j < matrix[i].length; j++) {
        System.out.print(matrix[i][j] + " ");
      }
      System.out.println();
    }
  }
}
// Çıxış:
// Matrix elementi [1][1]: 5
// 1 2 3
// 4 5 6
// 7 8 9

import java.util.Arrays;

public class ArraysClassExample {
  public static void main(String[] args) {
    int[] numbers = {5, 2, 8, 1, 9};
    Arrays.sort(numbers);
    String sortedArray = Arrays.toString(numbers);
    System.out.println("Sıralanmış massiv: " + sortedArray);
    int[] filledArray = new int[3];
    Arrays.fill(filledArray, 7);
    System.out.println("Doldurulmuş massiv: " + Arrays.toString(filledArray));
  }
}
// Çıxış:
// Sıralanmış massiv: [1, 2, 5, 8, 9]
// Doldurulmuş massiv: [7, 7, 7]

